import (
	"math"
	"sort"
)

func solve(nums []int64) int64 {
	abs := make([]int64, len(nums))
	for i := 0; i < len(nums); i++ {
		abs[i] = int64(math.Abs(float64(nums[i])))
	}
	sort.Ints(abs)
	var total int64
	for i := 0; i < len(abs); i++ {
		target := 2 * abs[i]
		low := i + 1
		high := len(abs) - 1
		res := i
		for low <= high {
			mid := (low + high) / 2
			if abs[mid] <= target {
				res = mid
				low = mid + 1
			} else {
				high = mid - 1
			}
		}
		total += int64(res - i)
	}
	return total
}
